forge solve(w, ch) {
  0 -> count
  walk i across range(count(w)) {
    when w @ i = ch {
      count + 1 -> count
    }
  }
  give count
}
emit solve("hello", "o")

forge solve(n) {
  when n = 0 { give 1 }
  1 -> result
  1 -> i
  sustain i <= n {
    result * i -> result
    i + 1 -> i
  }
  give result
}
emit solve(5)

forge solve(a, b) {
  when b = 0 { give a }
  sustain b != 0 {
    a % b -> temp
    b -> a
    temp -> b
  }
  give a
}

emit solve(12, 18)

forge solve(xs) {
  when count(xs) <= 1 { give yes }
  0 -> i
  sustain i < count(xs) - 1 {
    when xs @ i > xs @ (i + 1) { give no }
    i + 1 -> i
  }
  give yes
}
emit solve([1, 2, 3, 4])

forge gcd(a, b) {
  sustain b != 0 {
    a % b -> temp
    b -> a
    temp -> b
  }
  give a
}

forge solve(a, b) {
  a * b -> product
  gcd(a, b) -> gcd_val
  product / gcd_val -> result
  give result
}

emit solve(12, 18)

forge solve(xs) {
  xs @ 0 -> max
  walk i across range(1, count(xs)) {
    when xs @ i > max {
      xs @ i -> max
    }
  }
  give max
}
emit solve([3, 7, 2, 9, 4])

forge solve(n) {
  when n = 0 { give 0 }
  when n = 1 { give 1 }
  otherwise {
    0 -> a
    1 -> b
    sustain n > 1 {
      a + b -> c
      b -> a
      c -> b
      n - 1 -> n
    }
    give b
  }
}
emit solve(10)

forge solve(w) {
  when count(w) = 0 { give yes }
  0 -> i
  sustain i < count(w) / 2 {
    when w @ i != w @ (count(w) - 1 - i) { give no }
    i + 1 -> i
  }
  give yes
}
emit solve("racecar")

forge solve(b, e) {
  1 -> result
  sustain e > 0 {
    result * b -> result
    e - 1 -> e
  }
  give result
}
emit solve(2, 3)

forge solve(w) {
  "" -> result
  walk i across range(count(w)) {
    count(w) - 1 - i -> idx
    w @ idx -> char
    result + char -> result
  }
  give result
}
emit solve("hello")
